import pytest
import asyncio
from unittest.mock import MagicMock, patch
from main import (
    detect_deadlocks,
    validate_cache_performance,
    compare_cache_libraries,
    AsyncUser,
    validate_async_stability
)

# ======================
# Tests pour detect_deadlocks
# ======================

def test_detect_deadlocks_no_deadlock():
    """Test nominal : Aucun deadlock détecté"""
    threads = [
        {"thread_id": "1", "state": "RUNNING", "waiting_for": None, "stack_trace": [], "timestamp": "2023-11-15T14:30:00Z"},
        {"thread_id": "2", "state": "RUNNING", "waiting_for": None, "stack_trace": [], "timestamp": "2023-11-15T14:30:01Z"}
    ]
    result = detect_deadlocks(threads, threshold_seconds=5)
    assert result == {"has_deadlock": False, "cycles": []}

def test_detect_deadlocks_single_deadlock():
    """Test limite : Détection d'un deadlock simple (cycle de 2 threads)"""
    threads = [
        {"thread_id": "1", "state": "BLOCKED", "waiting_for": "lock_0x7f8a1c", "stack_trace": ["File \"test.py\", line 42, in async_task", "await lock.acquire()"], "timestamp": "2023-11-15T14:30:00Z"},
        {"thread_id": "2", "state": "BLOCKED", "waiting_for": "lock_0x7f8a1c", "stack_trace": ["File \"test.py\", line 43, in async_task", "await lock.acquire()"], "timestamp": "2023-11-15T14:30:01Z"}
    ]
    result = detect_deadlocks(threads, threshold_seconds=5)
    assert result == {
        "has_deadlock": True,
        "cycles": [
            {
                "threads": ["1", "2"],
                "lock": "lock_0x7f8a1c",
                "duration_seconds": 1
            }
        ]
    }

def test_detect_deadlocks_threshold_exceeded():
    """Test limite : Deadlock confirmé après 5 secondes"""
    threads = [
        {"thread_id": "1", "state": "BLOCKED", "waiting_for": "lock_0x7f8a1c", "stack_trace": [], "timestamp": "2023-11-15T14:29:55Z"},
        {"thread_id": "2", "state": "BLOCKED", "waiting_for": "lock_0x7f8a1c", "stack_trace": [], "timestamp": "2023-11-15T14:29:56Z"}
    ]
    result = detect_deadlocks(threads, threshold_seconds=5)
    assert result == {"has_deadlock": True, "cycles": [{"threads": ["1", "2"], "lock": "lock_0x7f8a1c", "duration_seconds": 11}]}

def test_detect_deadlocks_threshold_not_exceeded():
    """Test limite : Deadlock non confirmé avant 5 secondes"""
    threads = [
        {"thread_id": "1", "state": "BLOCKED", "waiting_for": "lock_0x7f8a1c", "stack_trace": [], "timestamp": "2023-11-15T14:30:00Z"},
        {"thread_id": "2", "state": "BLOCKED", "waiting_for": "lock_0x7f8a1c", "stack_trace": [], "timestamp": "2023-11-15T14:30:01Z"}
    ]
    result = detect_deadlocks(threads, threshold_seconds=5)
    assert result == {"has_deadlock": False, "cycles": []}

