def test_compare_cache_libraries_nominal():
    """Test nominal : Comparaison des bibliothèques avec données valides"""
    benchmarks = {
        "cachetools": {"p99_latency_ms": 0.8, "throughput_ops_s": 120000, "memory_overhead_percent": 8.0},
        "fastcache": {"p99_latency_ms": 0.5, "throughput_ops_s": 150000, "memory_overhead_percent": 5.0},
        "Caffeine": {"p99_latency_ms": 1.2, "throughput_ops_s": 90000, "memory_overhead_percent": 12.0}
